1	<script lang="ts">
2	  import type { Component } from 'svelte';
3	  import { focusState } from './focus.svelte';
4	  import { componentRegistry } from '$content/elements';
5	  import { elements } from '$content/slides.config';
6	
7	  let loadedComponent = $state<Component<any> | null>(null);
8	
9	  $effect(() => {
10	    if (!focusState.activeId) {
11	      loadedComponent = null;
12	      return;
13	    }
14	
15	    const elConfig = elements.find((e) => e.id === focusState.activeId);
16	    if (!elConfig) return;
17	
18	    const componentName = elConfig.focusComponent ?? elConfig.component;
19	    const loader = componentRegistry[componentName];
20	    if (!loader) return;
21	
22	    loader().then((mod) => {
23	      loadedComponent = mod.default;
24	    });
25	  });
26	
27	  function handleClose() {
28	    focusState.unfocus();
29	  }
30	
31	  function handleKeydown(e: KeyboardEvent) {
32	    if (e.key === 'Escape') {
33	      handleClose();
34	    }
35	  }
36	</script>
37	
