// === Side rails (camera-tracking overlays in the empty column space) ===
//
// The segment is 1920 wide, chat column ~820 centered -> ~550px empty per side.
// We place compact rails there and pin their y to the viewport top by deriving
// a world-y offset from camera.y. The rails live in world-space so they inherit
// the segment's transform, which is desirable (they scale if we ever zoom).

// Rough y at which the main headline has left the viewport.
const HEADLINE_BOTTOM = 360;

const vpWorldHeight = $derived(camera.viewportHeight / camera.zoom);
const viewportTopY = $derived(camera.y - vpWorldHeight / 2);
const railTopY = $derived(viewportTopY + 120);

const leftRailVisible = $derived(viewportTopY > HEADLINE_BOTTOM - 40);

