  border-top: 1px solid var(--color-code-border);
  padding: 14px 16px;
  overflow-x: auto;
  color: var(--color-text);
  margin: 12px 0 0;
  white-space: pre;
}

.code code {
  font-family: inherit;
}

.tool-output {
  padding: 10px 16px 14px;
  border-top: 1px solid var(--color-border);
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.tool-output.error {
  background: rgba(248, 113, 113, 0.06);
}

.tool-output pre {
  margin: 0;
  padding: 10px 12px;
  border: none;
  background: rgba(0, 0, 0, 0.3);
  border-radius: 6px;
  font-size: 13px;
  color: var(--color-text-muted);
}

.tool-output.error pre {
  color: var(--color-error);
}

.output-label {
  font-family: var(--font-mono);
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.14em;
  color: var(--color-text-subtle);
}

/* --- summary, separator, aside --- */

.summary-line {
  margin-left: 46px;
  font-size: 14px;
  color: var(--color-text-muted);
  font-family: var(--font-mono);
}

.summary-line code {
  background: rgba(0, 0, 0, 0.25);
  padding: 1px 6px;
  border-radius: 4px;
}

.separator {
  display: flex;
  align-items: center;
  gap: 12px;
  margin: 8px 0 4px;
  color: var(--color-text-subtle);
  font-family: var(--font-mono);
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.22em;
}

.separator::before,
.separator::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--color-border);
}

.aside {
  margin-left: 46px;
  font-size: 15px;
  color: var(--color-text-muted);
  line-height: 1.55;
}

.aside-pill {
  display: inline-block;
  padding: 1px 8px;
  border-radius: 9999px;
  background: var(--color-ai-soft);
  border: 1px solid var(--color-tool-border);
  font-family: var(--font-mono);
  font-size: 0.85em;
  color: var(--color-text);
  margin: 0 3px;
}

/* --- search + sources --- */

.search-queries {
  list-style: none;
  padding: 14px 16px 4px;
  display: flex;
  flex-direction: column;
  gap: 4px;
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--color-text-muted);
}

.q-verb {
  color: var(--color-ai-mid);
  margin-right: 6px;
}

.search-results {
  list-style: none;
  padding: 8px 16px 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.search-results li {
  padding: 12px 14px;
  background: rgba(0, 0, 0, 0.28);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
}

.sr-host {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--color-text-subtle);
  text-transform: lowercase;
  letter-spacing: 0.04em;
}

.sr-title {
  font-size: 15px;
  font-weight: 500;
  margin-top: 2px;
  color: var(--color-text);
}

.sr-excerpt {
  font-size: 13px;
  color: var(--color-text-muted);
  margin-top: 4px;
  line-height: 1.45;
}

.source-excerpt {
  margin-left: 46px;
  border: 1px solid var(--color-border);
  border-left: 3px solid var(--color-ai-mid);
  background: rgba(255, 255, 255, 0.02);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  padding: 14px 20px;
}

.se-host {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--color-text-subtle);
  margin-bottom: 8px;
}

blockquote {
  font-size: 16px;
  line-height: 1.55;
  color: var(--color-text);
  font-style: italic;
}

.tail-spacer {
  height: 240px;
}

/* --- side rails --- */

.left-rail,
.right-rail {
  position: absolute;
  top: 0;
  left: 0;
  transform-origin: 0 0;
  pointer-events: none;
}

.left-rail {
  width: 400px;
  opacity: 0;
  transition: opacity 0.55s ease;
}

.left-rail.visible {
  opacity: 1;
}

.lr-eyebrow {
  display: inline-block;
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-text-subtle);
  margin-bottom: 12px;
}

.lr-headline {
  font-family: var(--font-sans);
